int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;
    if (k <= c)
        return c;
    else
        return k;
}

void needle_omp_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    for (int bx = 0; bx < i; bx++) {
        int b_index_x = bx;
        int b_index_y = i - 1 - bx;

        int index    = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols + 1);
        int index_n  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 1;
        int index_w  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
        int index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
        int ref[BLOCK_SIZE][BLOCK_SIZE];

        temp[0][0] = matrix_cuda[index_nw];

        for (int ty = 0; ty < BLOCK_SIZE; ty++)
            for (int tx = 0; tx < BLOCK_SIZE; tx++)
                ref[ty][tx] = referrence[index + cols * ty + tx];

        for (int tx = 0; tx < BLOCK_SIZE; tx++)
            temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];

        for (int tx = 0; tx < BLOCK_SIZE; tx++)
            temp[0][tx + 1] = matrix_cuda[index_n + tx];

        for (int m = 0; m < BLOCK_SIZE; m++) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;
                temp[t_index_y][t_index_x] = maximum(
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1] - penalty,
                    temp[t_index_y-1][t_index_x] - penalty
                );
            }
        }

        for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;
                temp[t_index_y][t_index_x] = maximum(
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1] - penalty,
                    temp[t_index_y-1][t_index_x] - penalty
                );
            }
        }

        for (int ty = 0; ty < BLOCK_SIZE; ty++)
            for (int tx = 0; tx < BLOCK_SIZE; tx++)
                matrix_cuda[index + ty * cols + tx] = temp[ty+1][tx+1];
    }
}

void needle_omp_shared_2(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    for (int bx = 0; bx < i; bx++) {
        int b_index_x = bx + block_width - i;
        int b_index_y = block_width - bx - 1;

        int index    = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols + 1);
        int index_n  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 1;
        int index_w  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
        int index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
        int ref[BLOCK_SIZE][BLOCK_SIZE];

        for (int ty = 0; ty < BLOCK_SIZE; ty++)
            for (int tx = 0; tx < BLOCK_SIZE; tx++)
                ref[ty][tx] = referrence[index + cols * ty + tx];

        temp[0][0] = matrix_cuda[index_nw];

        for (int tx = 0; tx < BLOCK_SIZE; tx++)
            temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];

        for (int tx = 0; tx < BLOCK_SIZE; tx++)
            temp[0][tx + 1] = matrix_cuda[index_n + tx];

        for (int m = 0; m < BLOCK_SIZE; m++) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;
                temp[t_index_y][t_index_x] = maximum(
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1] - penalty,
                    temp[t_index_y-1][t_index_x] - penalty
                );
            }
        }

        for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;
                temp[t_index_y][t_index_x] = maximum(
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1] - penalty,
                    temp[t_index_y-1][t_index_x] - penalty
                );
            }
        }

        for (int ty = 0; ty < BLOCK_SIZE; ty++)
            for (int tx = 0; tx < BLOCK_SIZE; tx++)
                matrix_cuda[index + ty * cols + tx] = temp[ty+1][tx+1];
    }
}

