#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x)
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel_omp(
    int iteration,
    int *gpuWall,
    int *gpuSrc,
    int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int blockCols)
{
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blockCols; bx++)
    {
        int prev[BLOCK_SIZE];
        int res[BLOCK_SIZE];
        bool computed_arr[BLOCK_SIZE];

        int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;

        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

        // Load prev from gpuSrc
        for (int tx = 0; tx < BLOCK_SIZE; tx++)
        {
            int xidx = blkX + tx;
            prev[tx] = 0;
            res[tx] = 0;
            computed_arr[tx] = false;
            if (IN_RANGE(xidx, 0, cols-1))
            {
                prev[tx] = gpuSrc[xidx];
            }
        }

        for (int i = 0; i < iteration; i++)
        {
            for (int tx = 0; tx < BLOCK_SIZE; tx++)
                computed_arr[tx] = false;

            // Compute W, E, isValid for each thread
            int W_arr[BLOCK_SIZE], E_arr[BLOCK_SIZE];
            bool isValid_arr[BLOCK_SIZE];

            for (int tx = 0; tx < BLOCK_SIZE; tx++)
            {
                int W = tx - 1;
                int E = tx + 1;
                W = (W < validXmin) ? validXmin : W;
                E = (E > validXmax) ? validXmax : E;
                W_arr[tx] = W;
                E_arr[tx] = E;
                isValid_arr[tx] = IN_RANGE(tx, validXmin, validXmax);
            }

            for (int tx = 0; tx < BLOCK_SIZE; tx++)
            {
                int xidx = blkX + tx;
                if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid_arr[tx])
                {
                    computed_arr[tx] = true;
                    int left = prev[W_arr[tx]];
                    int up = prev[tx];
                    int right = prev[E_arr[tx]];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int index = cols * (startStep + i) + xidx;
                    res[tx] = shortest + gpuWall[index];
                }
            }

            if (i == iteration - 1)
                break;

            for (int tx = 0; tx < BLOCK_SIZE; tx++)
            {
                if (computed_arr[tx])
                    prev[tx] = res[tx];
            }
        }

        // Write results back
        for (int tx = 0; tx < BLOCK_SIZE; tx++)
        {
            int xidx = blkX + tx;
            if (computed_arr[tx])
            {
                gpuResults[xidx] = res[tx];
            }
        }
    }
}

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols,
              int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;
    for (int t = 0; t < rows-1; t += pyramid_height)
    {
        int temp = src;
        src = dst;
        dst = temp;

        int iteration = MIN(pyramid_height, rows-t-1);

        dynproc_kernel_omp(
            iteration,
            gpuWall,
            gpuResult[src],
            gpuResult[dst],
            cols, rows, t, borderCols, blockCols);
    }
    return dst;
}

