        int temp = src;
        src = dst;
        dst = temp;

        int iteration = MIN(pyramid_height, rows-t-1);

        dynproc_kernel_omp(
            iteration,
            gpuWall,
            gpuResult[src],
            gpuResult[dst],
            cols, rows, t, borderCols, blockCols);
    }
    return dst;
}

