// OpenMP equivalent of srad_cuda_1
void srad_omp_1(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float q0sqr)
{
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            float jc = J_cuda[index];

            // North neighbor
            int i_n = (i == 0) ? 0 : i - 1;
            // South neighbor
            int i_s = (i == rows - 1) ? rows - 1 : i + 1;
            // West neighbor
            int j_w = (j == 0) ? 0 : j - 1;
            // East neighbor
            int j_e = (j == cols - 1) ? cols - 1 : j + 1;

            float n = J_cuda[i_n * cols + j] - jc;
            float s = J_cuda[i_s * cols + j] - jc;
            float w = J_cuda[i * cols + j_w] - jc;
            float e = J_cuda[i * cols + j_e] - jc;

            float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
            float l  = (n + s + w + e) / jc;

            float num  = (0.5f * g2) - ((1.0f / 16.0f) * (l * l));
            float den  = 1.0f + (0.25f * l);
            float qsqr = num / (den * den);

            // diffusion coefficient (equ 33)
            den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            float c = 1.0f / (1.0f + den);

            // saturate diffusion coefficient
            if (c < 0.0f)       c = 0.0f;
            else if (c > 1.0f)  c = 1.0f;

            C_cuda[index] = c;
            E_C[index] = e;
            W_C[index] = w;
            S_C[index] = s;
            N_C[index] = n;
        }
    }
}

// OpenMP equivalent of srad_cuda_2
void srad_omp_2(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float lambda,
    float q0sqr)
{
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            float cc = C_cuda[index];

            // South coefficient
            float cs;
            if (i == rows - 1)
                cs = C_cuda[(rows - 1) * cols + j];
            else
                cs = C_cuda[(i + 1) * cols + j];

            // East coefficient
            float ce;
            if (j == cols - 1)
                ce = C_cuda[i * cols + (cols - 1)];
            else
                ce = C_cuda[i * cols + (j + 1)];

            float cn = cc;
            float cw = cc;

            // divergence (equ 58)
            float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];

            // image update (equ 61)
            J_cuda[index] = J_cuda[index] + 0.25f * lambda * d_sum;
        }
    }
}

