    for (int by = 0; by < block_y; by++) {
        for (int bx = 0; bx < block_x; bx++) {
            float temp[BLOCK_SIZE][BLOCK_SIZE];
            float temp_result[BLOCK_SIZE][BLOCK_SIZE];
            float north[BLOCK_SIZE][BLOCK_SIZE];
            float south[BLOCK_SIZE][BLOCK_SIZE];
            float east_arr[BLOCK_SIZE][BLOCK_SIZE];
            float west_arr[BLOCK_SIZE][BLOCK_SIZE];

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index_n = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + tx - cols;
                    int index_s = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * BLOCK_SIZE + tx;
                    int index_w = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty - 1;
                    int index_e = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + BLOCK_SIZE;
                    int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    north[ty][tx] = J_cuda[index_n];
                    south[ty][tx] = J_cuda[index_s];

                    if (by == 0) {
                        north[ty][tx] = J_cuda[BLOCK_SIZE * bx + tx];
                    } else if (by == block_y - 1) {
                        south[ty][tx] = J_cuda[cols * BLOCK_SIZE * (block_y - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
                    }

                    west_arr[ty][tx] = J_cuda[index_w];
                    east_arr[ty][tx] = J_cuda[index_e];

                    if (bx == 0) {
                        west_arr[ty][tx] = J_cuda[cols * BLOCK_SIZE * by + cols * ty];
                    } else if (bx == block_x - 1) {
                        east_arr[ty][tx] = J_cuda[cols * BLOCK_SIZE * by + BLOCK_SIZE * (block_x - 1) + cols * ty + BLOCK_SIZE - 1];
                    }

                    temp[ty][tx] = J_cuda[index];
                }
            }

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    float jc = temp[ty][tx];
                    float n, s, w, e;

                    if (ty == 0 && tx == 0) {
                        n = north[ty][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = west_arr[ty][tx] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (ty == 0 && tx == BLOCK_SIZE-1) {
                        n = north[ty][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = east_arr[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE-1 && tx == BLOCK_SIZE-1) {
                        n = temp[ty-1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = east_arr[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE-1 && tx == 0) {
                        n = temp[ty-1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = west_arr[ty][tx] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (ty == 0) {
                        n = north[ty][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (tx == BLOCK_SIZE-1) {
                        n = temp[ty-1][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = east_arr[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE-1) {
                        n = temp[ty-1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (tx == 0) {
                        n = temp[ty-1][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = west_arr[ty][tx] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else {
                        n = temp[ty-1][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = temp[ty][tx+1] - jc;
                    }

                    float g2 = (n*n + s*s + w*w + e*e) / (jc*jc);
                    float l  = (n + s + w + e) / jc;
                    float num  = (0.5f*g2) - ((1.0f/16.0f)*(l*l));
                    float den  = 1.0f + (0.25f*l);
                    float qsqr = num / (den*den);

                    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
                    float c_val = 1.0f / (1.0f + den);

                    if (c_val < 0.0f) temp_result[ty][tx] = 0.0f;
                    else if (c_val > 1.0f) temp_result[ty][tx] = 1.0f;
                    else temp_result[ty][tx] = c_val;

                    C_cuda[index] = temp_result[ty][tx];
                    E_C[index] = e;
                    W_C[index] = w;
                    S_C[index] = s;
                    N_C[index] = n;
                }
            }
        }
    }
}

// OpenMP kernel 2: update image
void srad_omp_2(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float lambda,
    float q0sqr
)
{
    int block_x = cols / BLOCK_SIZE;
    int block_y = rows / BLOCK_SIZE;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < block_y; by++) {
        for (int bx = 0; bx < block_x; bx++) {
            float south_c[BLOCK_SIZE][BLOCK_SIZE];
            float east_c[BLOCK_SIZE][BLOCK_SIZE];
            float c_cuda_temp[BLOCK_SIZE][BLOCK_SIZE];
            float c_cuda_result[BLOCK_SIZE][BLOCK_SIZE];
            float temp[BLOCK_SIZE][BLOCK_SIZE];

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    int index_s = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * BLOCK_SIZE + tx;
                    int index_e = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + BLOCK_SIZE;

                    temp[ty][tx] = J_cuda[index];

                    south_c[ty][tx] = C_cuda[index_s];
                    if (by == block_y - 1) {
                        south_c[ty][tx] = C_cuda[cols * BLOCK_SIZE * (block_y - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
                    }

                    east_c[ty][tx] = C_cuda[index_e];
                    if (bx == block_x - 1) {
                        east_c[ty][tx] = C_cuda[cols * BLOCK_SIZE * by + BLOCK_SIZE * (block_x - 1) + cols * ty + BLOCK_SIZE - 1];
                    }

                    c_cuda_temp[ty][tx] = C_cuda[index];
                }
            }

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    float cc = c_cuda_temp[ty][tx];
                    float cn, cs, cw, ce;

                    if (ty == BLOCK_SIZE-1 && tx == BLOCK_SIZE-1) {
                        cn = cc;
                        cs = south_c[ty][tx];
                        cw = cc;
                        ce = east_c[ty][tx];
                    } else if (tx == BLOCK_SIZE-1) {
                        cn = cc;
                        cs = c_cuda_temp[ty+1][tx];
                        cw = cc;
                        ce = east_c[ty][tx];
                    } else if (ty == BLOCK_SIZE-1) {
                        cn = cc;
                        cs = south_c[ty][tx];
                        cw = cc;
                        ce = c_cuda_temp[ty][tx+1];
                    } else {
                        cn = cc;
                        cs = c_cuda_temp[ty+1][tx];
                        cw = cc;
                        ce = c_cuda_temp[ty][tx+1];
                    }

                    float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];
                    c_cuda_result[ty][tx] = temp[ty][tx] + 0.25f * lambda * d_sum;

                    J_cuda[index] = c_cuda_result[ty][tx];
                }
            }
        }
    }
}

