/* this structure represents a point */
typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

/* this is the array of points */
typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t
{
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
